void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = 5*vUv;
uv1 = uv0;
d= length(uv1);

for ( int n=0; (n <5) && (n<14*d) ; n++ )
{
uv1 += sin(uv1.yx+par.yx) + uv0 - par;
d=fract(.1*length(uv1));
